-- ملء محتوى عنقود "الفتاوى الموثقة" (fatawa-muwaththaqa) — ستة تصنيفات
-- فرعية draft بالكامل: فتاوى العبادات (fatawa-ibadat)، فتاوى الأسرة
-- (fatawa-usrah)، فتاوى المعاملات (fatawa-muamalat)، فتاوى طبية
-- (fatawa-tibbiyya)، فتاوى تقنية (fatawa-tiqniyya)، فتاوى الذكاء
-- الاصطناعي (fatawa-ai). كل تصنيف يحصل على درس واحد (lessons +
-- lesson_sections + lesson_citations)، بأسلوب الدفعات السابقة (body +
-- examples). خصوصية هذا العنقود أن موضوعه فتاوى فعلية من جهات إفتاء
-- معتمدة مسمّاة صراحة (لا نصوص دينية أصلية)، لذا استُخدم
-- lesson_citations.source_type='fatwa_body' (القيمة المخصصة لهذا
-- النوع في قيد lesson_citations_source_type_check) لكل الاستشهادات
-- الست، بعد التحقق من كل فتوى عبر WebSearch/WebFetch من مصدرها
-- الرسمي مباشرة:
-- 1) فتاوى العبادات: إسلام ويب - مركز الفتوى، فتوى رقم 197189 (حكم
--    الجمع والقصر في السفر، 27-1-2013م).
-- 2) فتاوى الأسرة: إسلام ويب - مركز الفتوى، فتوى رقم 296344 (هل يجب
--    على المرأة العاملة المشاركة في نفقة بيت الزوجية، 17-5-2015م).
-- 3) فتاوى المعاملات: دار الإفتاء المصرية، فتوى رقم 8924 (حكم البيع
--    بالتقسيط والفرق بينه وبين الربا، 9 أبريل 2026م، مفتي الجمهورية
--    أ.د/ نظير محمد عياد).
-- 4) فتاوى طبية: مجمع الفقه الإسلامي الدولي، القرار رقم 26 (1/4)
--    بشأن انتفاع الإنسان بأعضاء جسم إنسان آخر حيًّا كان أو ميتًا
--    (الدورة الرابعة، جدة، 1408هـ/1988م).
-- 5) فتاوى تقنية: مجمع الفقه الإسلامي الدولي، القرار رقم 237 (8/24)
--    بشأن العملات الإلكترونية المشفرة (الدورة الرابعة والعشرون، دبي،
--    1441هـ/2019م).
-- 6) فتاوى الذكاء الاصطناعي: دار الإفتاء المصرية، فتوى رقم 8784 (حكم
--    استخدام تطبيقات الذكاء الاصطناعي AI في الاستفتاء، 22 سبتمبر
--    2025م، مفتي الجمهورية أ.د/ نظير محمد عياد).
-- ثماني آيات تحقَّقت حرفياً محليًا من
-- artifacts/majalis/public/data/quran عبر numberInSurah: النساء 101
-- (قصر الصلاة في السفر)، البقرة 275 (أحل الله البيع وحرم الربا)،
-- النساء 34 (قوامة الرجال بالإنفاق)، المائدة 32 (من أحياها فكأنما
-- أحيا الناس جميعًا)، النساء 29 (النهي عن قتل النفس)، البقرة 219
-- (الموازنة بين الإثم والمنفعة)، النحل 43 (فاسألوا أهل الذكر). خمسة
-- أحاديث استُشهد بها، تحقَّقت عبر WebSearch قبل الإدراج (كلها متفق
-- عليها أو في الصحيحين إلا حديث جابر في حجة الوداع فمسلم منفردًا):
-- حديث عائشة في فرض الصلاة ركعتين (البخاري 350، مسلم 685)، حديث
-- جابر الطويل في صفة حجة الوداع «ولهن عليكم رزقهن وكسوتهن بالمعروف»
-- (مسلم 1218)، حديث ابن عباس في السلم «من أسلف في شيء ففي كيل معلوم»
-- (البخاري 2240 ومسلم)، حديث أبي هريرة في النهي عن بيع الغرر (مسلم
-- 1513)، حديث عبد الله بن عمرو بن العاص في قبض العلم بقبض العلماء
-- (البخاري 100، مسلم 2673).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الستة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) فتاوى العبادات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='67f8f593-0ff2-4d3f-8a41-4f960271cbbb' AND title='حكم قصر الصلاة وجمعها للمسافر: الرخصة وضوابطها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم قصر الصلاة وجمعها للمسافر: الرخصة وضوابطها', 'بيان رخصة قصر الصلاة الرباعية وجمعها للمسافر وشروط الانتفاع بهذه الرخصة كما جاء في فتوى إسلام ويب رقم 197189', '67f8f593-0ff2-4d3f-8a41-4f960271cbbb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'رخصة القصر والجمع: متى تثبت ومتى تسقط', 'قصر الصلاة الرباعية للمسافر سنة مؤكدة إذا كان سفره سفرًا مباحًا يبلغ المسافة المعتبرة شرعًا، وحيث ثبتت له رخصة القصر جاز له كذلك أن يجمع بين الظهر والعصر، وبين المغرب والعشاء، جمع تقديم أو جمع تأخير بحسب ما هو أرفق به. وصفة الجمع أن يؤذن ويقيم ويصلي الصلاة الأولى ركعتين ثم يقيم للصلاة الثانية فيصليها ركعتين أيضًا دون أذان ثانٍ. وتبقى هذه الرخصة قائمة للمسافر ما دام على سفره ولم ينوِ إقامة مستقرة، فإذا نوى المسافر الإقامة في بلد أربعة أيام فأكثر سقط عنه حكم القصر والجمع وعاد إلى الصلاة تامة كالمقيم، لأن الرخصة إنما شُرعت مراعاة لمشقة السفر لا لمجرد الخروج من البلد.', 1),
    (v_lesson, 'examples', 'آية إباحة القصر وحديث فرض الصلاة ركعتين', 'قال تعالى: ﴿وَإِذَا ضَرَبْتُمْ فِي الْأَرْضِ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَقْصُرُوا مِنَ الصَّلَاةِ إِنْ خِفْتُمْ أَن يَفْتِنَكُمُ الَّذِينَ كَفَرُوا﴾ (النساء: 101)، وهي الأصل القرآني الصريح في إباحة قصر الصلاة للمسافر. وفي بيان أصل هذه الرخصة، عن عائشة رضي الله عنها قالت: "فرض الله الصلاة حين فرضها ركعتين ركعتين، في الحضر والسفر، فأقرت صلاة السفر، وزيد في صلاة الحضر" (متفق عليه، رواه البخاري 350 ومسلم 685). فهذا الحديث يبيّن أن صلاة السفر ليست ترخصًا طارئًا بل هي الأصل الذي فُرضت عليه الصلاة أول مرة، وإنما زيدت صلاة الحضر تكريمًا للمقيم المستقر لا تخفيفًا عن المسافر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'إسلام ويب - مركز الفتوى، فتوى رقم 197189: حكم الجمع والقصر في السفر (27-1-2013م)', 1);
  END IF;

  -- 2) فتاوى الأسرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5cbe4302-042a-4b30-864b-48d159d27bcf' AND title='حكم نفقة الزوجة العاملة وملكيتها لراتبها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم نفقة الزوجة العاملة وملكيتها لراتبها', 'بيان أن راتب المرأة العاملة ملك خالص لها وأن نفقة البيت تبقى واجبة على الزوج كما جاء في فتوى إسلام ويب رقم 296344', '5cbe4302-042a-4b30-864b-48d159d27bcf', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'راتب الزوجة حق خالص لها ونفقة البيت واجبة على الزوج', 'ما تكسبه المرأة من راتب عملها حق خالص لها لا يجوز لزوجها أن يأخذ منه شيئًا أو يُجبرها على المشاركة به في نفقة البيت، إلا أن تشارك من طيب نفسها ورضاها فتلك زيادة في المودة بينهما لا واجب عليها. ونفقة البيت من مسكن ومأكل وحاجات الأسرة تبقى واجبة على الزوج ولو كانت زوجته عاملة، ما لم يشترط عليها المشاركة في النفقة عند العقد أو يجرِ بذلك عرف معتبر بينهما، فحينئذ يُعمل بما اتُّفق عليه. وإذا امتنع الزوج عن الإنفاق مع قدرته عليه فذلك ظلم لها وتفريط في حق واجب، لكن هذا لا يسقط عنها واجباتها الزوجية كطاعته في المعروف، إذ لا صلة بين استحقاقها لراتبها وبين ما عليها من حقوق زوجية أخرى.', 1),
    (v_lesson, 'examples', 'آية قوامة الرجال بالإنفاق وحديث حق الزوجة في الرزق والكسوة', 'قال تعالى: ﴿الرِّجَالُ قَوَّامُونَ عَلَى النِّسَاءِ بِمَا فَضَّلَ اللَّهُ بَعْضَهُمْ عَلَىٰ بَعْضٍ وَبِمَا أَنفَقُوا مِنْ أَمْوَالِهِمْ﴾ (النساء: 34)، ربطت قوامة الرجل على أسرته بإنفاقه عليها، فالنفقة أصل من أصول هذه القوامة لا يسقط بعمل الزوجة أو غناها. وفي بيان حق الزوجة على زوجها في الرزق والكسوة، عن جابر بن عبد الله رضي الله عنه في حديثه الطويل المعروف بصفة حجة الوداع، أن النبي صلى الله عليه وسلم قال في خطبته يوم عرفة عن حقوق النساء: "ولهن عليكم رزقهن وكسوتهن بالمعروف" (رواه مسلم 1218). فهذا الحديث نص صريح على أن رزق الزوجة وكسوتها بالمعروف حق واجب لها على زوجها، لا صلة له بما تملكه هي من راتب أو مال خاص.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'إسلام ويب - مركز الفتوى، فتوى رقم 296344: هل يجب على المرأة العاملة المشاركة في نفقة بيت الزوجية (17-5-2015م)', 1);
  END IF;

  -- 3) فتاوى المعاملات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c442511e-f2ac-4ddd-96bf-ac25d1d66a28' AND title='حكم البيع بالتقسيط بزيادة عن الثمن النقدي والفرق بينه وبين الربا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم البيع بالتقسيط بزيادة عن الثمن النقدي والفرق بينه وبين الربا', 'بيان جواز البيع بالتقسيط مع زيادة معلومة على الثمن النقدي وتوضيح الفرق الجوهري بينه وبين الربا المحرم كما جاء في فتوى دار الإفتاء المصرية رقم 8924', 'c442511e-f2ac-4ddd-96bf-ac25d1d66a28', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'زيادة الثمن مقابل الأجل جزء من عقد البيع لا زيادة على قرض', 'لا مانع شرعًا من بيع السلع بالتقسيط مع زيادة معلومة على الثمن الأصلي مقابل أجل معلوم، وهو جائز كالبيع النقدي من غير فرق بينهما في أصل الإباحة، بشرط أن يُحدَّد الثمن الإجمالي وأجل السداد وقت العقد تحديدًا معلومًا لا جهالة فيه ولا اضطراب. والفرق الجوهري بين هذه الزيادة وبين الربا المحرم أن زيادة التقسيط جزء من ثمن السلعة المعقود عليه في عقد بيع تام الأركان، بخلاف الربا الذي هو زيادة مشروطة على أصل قرض نقدي مجرد من غير سلعة تتوسط العقد. فتوسط السلعة في عقد البيع بالتقسيط هو ما ينفي عنه شبهة الربا، إذ العبرة في تحريم الربا بكونه فضلًا في قرض مال بمال، لا بكونه أجلًا في ثمن سلعة مبيعة.', 1),
    (v_lesson, 'examples', 'آية إحلال البيع وتحريم الربا وحديث السلم بأجل معلوم', 'قال تعالى: ﴿وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، وهي الأصل القرآني الفاصل بين حِلّ عقود البيع وحرمة الربا، وعليها يُبنى التمييز بين زيادة الثمن في عقد بيع تام وبين زيادة القرض الربوي. وفي بيان ضابط تحديد الأجل والمقدار في المعاملات المؤجلة، عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم قدم المدينة وهم يُسلفون في الثمار السنة والسنتين، فقال: "من أسلف في شيء، ففي كيل معلوم، ووزن معلوم، إلى أجل معلوم" (متفق عليه، رواه البخاري 2240 ومسلم). فهذا الحديث يرسي ضابطًا عامًا لكل معاملة مؤجلة، ومنها البيع بالتقسيط: أن يكون الثمن والأجل معلومين محددين وقت العقد، وبذلك ينتفي الغرر والجهالة اللذان يقعان مأخذًا شرعيًا حقيقيًا لو وُجدا لا مجرد كون الثمن مؤجلاً.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8924: حكم البيع بالتقسيط والفرق بينه وبين الربا (9 أبريل 2026م، مفتي الجمهورية أ.د/ نظير محمد عياد)', 1);
  END IF;

  -- 4) فتاوى طبية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='bd833bec-8230-4d1a-9731-f5f1d4a5d0b6' AND title='حكم التبرع بالأعضاء البشرية: ضوابط الجواز والمنع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم التبرع بالأعضاء البشرية: ضوابط الجواز والمنع', 'بيان الفروق بين صور نقل الأعضاء البشرية الجائزة والممنوعة كما فصّلها قرار مجمع الفقه الإسلامي الدولي رقم 26 (1/4)', 'bd833bec-8230-4d1a-9731-f5f1d4a5d0b6', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'صور الجواز وصور المنع في نقل الأعضاء', 'فصّل مجمع الفقه الإسلامي الدولي في قراره رقم 26 صور الانتفاع بأعضاء جسم الإنسان أحياءً أو أمواتًا. فيجوز نقل عضو من مكان في جسد الإنسان إلى مكان آخر من جسده نفسه إذا ترجحت فيه المصلحة على المفسدة، كما يجوز نقل ما يتجدد من الأعضاء كالدم والجلد بين شخصين حيَّين إذا كان المتبرع أهلًا للتبرع مختارًا غير مُكرَه. أما نقل عضو حيوي لا تستقيم حياة صاحبه بدونه، كالقلب، من إنسان حي إلى آخر فمحرم لا يجوز بحال، لأنه في معنى إهلاك المتبرع نفسه. وكذلك يحرم نقل عضو من حي تتوقف عليه وظيفة أساسية إن كان في نزعه ذهاب تلك الوظيفة بالكلية عن صاحبه، كنقل كلتا القرنتين معًا. أما نقل عضو من إنسان ميت لإنقاذ حياة معصومة أو استعادة وظيفة أساسية فجائز، بشرط إذن الميت في حياته أو إذن ورثته من بعده أو إذن ولي الأمر عند الحاجة وتعذر الإذنين السابقين، مع التشديد على تحريم بيع الأعضاء البشرية بيعًا مطلقًا في كل هذه الصور، لما في ذلك من امتهان لكرامة الجسد الإنساني.', 1),
    (v_lesson, 'examples', 'آية إحياء النفس الواحدة وآية النهي عن قتل النفس', 'قال تعالى: ﴿مَن قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ أَوْ فَسَادٍ فِي الْأَرْضِ فَكَأَنَّمَا قَتَلَ النَّاسَ جَمِيعًا وَمَنْ أَحْيَاهَا فَكَأَنَّمَا أَحْيَا النَّاسَ جَمِيعًا﴾ (المائدة: 32)، وهي الأصل القرآني الذي يُستند إليه في بيان عِظَم أجر إنقاذ حياة إنسان بأي وسيلة مشروعة، ومنها التبرع بعضو من ميت لإنقاذ حياة حي. وفي المقابل، قال تعالى: ﴿وَلَا تَقْتُلُوا أَنفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا﴾ (النساء: 29)، وهي الأصل الذي بنى عليه المجمع تحريم تبرع الحي بعضو حيوي يودي بحياته، إذ يدخل ذلك في معنى قتل النفس المنهي عنه، فلا يجوز تحت أي دافع من دوافع الإحسان إلى الغير أن يُهلك المرء نفسه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'مجمع الفقه الإسلامي الدولي، القرار رقم 26 (1/4): انتفاع الإنسان بأعضاء جسم إنسان آخر حيًّا كان أو ميتًا (الدورة الرابعة، جدة، 1408هـ/1988م)', 1);
  END IF;

  -- 5) فتاوى تقنية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='15b445c8-855e-4131-b764-f8c2406e33b7' AND title='الموقف الفقهي من العملات الرقمية المشفرة: بين الحذر والدراسة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الموقف الفقهي من العملات الرقمية المشفرة: بين الحذر والدراسة', 'بيان موقف مجمع الفقه الإسلامي الدولي من العملات الإلكترونية المشفرة كالبيتكوين وما نبّه إليه من مخاطرها كما جاء في القرار رقم 237 (8/24)', '15b445c8-855e-4131-b764-f8c2406e33b7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'توصية بالدراسة لا حكم قطعي، وتنبيه إلى الغرر والتقلب', 'بحث مجمع الفقه الإسلامي الدولي في دورته الرابعة والعشرين مسألة العملات الإلكترونية المشفرة، ومنها البيتكوين والإيثريوم، وهي أرقام مشفرة لا وجود مادي لها ولا رصيد حقيقي يضمنها، تُتداول بين الأطراف مباشرة دون وسيط رسمي معترف به. ولاحظ المجمع ما تنطوي عليه هذه العملات من مخاطر جسيمة أبرزها التقلب الحاد والسريع في قيمتها، وانعدام جهة رسمية ضامنة أو رقابة معتبرة عليها، وما يكتنف تداولها من جهالة وغرر بيّن. ولذلك لم يصدر المجمع حكمًا شرعيًا قطعيًا جامعًا في هذه المسألة المستجدة، بل أوصى بمزيد من البحث والدراسة الشرعية والاقتصادية المتخصصة لها، مع التنبيه إلى وجوب توخي الحذر الشديد في التعامل بها لما فيها من مخاطرة ظاهرة قد تصل إلى حد الغرر المحرم في بعض صورها.', 1),
    (v_lesson, 'examples', 'آية الموازنة بين النفع والإثم وحديث النهي عن بيع الغرر', 'قال تعالى: ﴿يَسْأَلُونَكَ عَنِ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ وَإِثْمُهُمَا أَكْبَرُ مِن نَّفْعِهِمَا﴾ (البقرة: 219)، وهي أصل قرآني في الموازنة بين ما في الشيء من نفع وما فيه من إثم ومخاطرة، وهو ميزان يصلح للاستئناس به عند النظر في أمر مستجد كالعملات الرقمية المشفرة التي أقرّ المجمع بما فيها من منافع وما فيها في الوقت نفسه من مخاطر جسيمة. وفي بيان الأصل الفقهي المحرِّم للمخاطرة والجهالة في المعاملات المالية، عن أبي هريرة رضي الله عنه: "أن رسول الله صلى الله عليه وسلم نهى عن بيع الحصاة، وعن بيع الغرر" (رواه مسلم 1513). فهذا الحديث هو الأصل الذي يُبنى عليه التحذير الشرعي من كل معاملة تغلب عليها الجهالة والمخاطرة غير المنضبطة، وهو ما استند إليه المجمع في التنبيه على مخاطر هذه العملات وتوصيته بمزيد من الدراسة قبل إصدار حكم قاطع فيها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'مجمع الفقه الإسلامي الدولي، القرار رقم 237 (8/24): بشأن العملات الإلكترونية (الدورة الرابعة والعشرون، دبي، 1441هـ/2019م)', 1);
  END IF;

  -- 6) فتاوى الذكاء الاصطناعي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='58268ad0-64e1-406b-8787-30de9fa077cd' AND title='حكم الاعتماد على تطبيقات الذكاء الاصطناعي في الحصول على الفتوى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الاعتماد على تطبيقات الذكاء الاصطناعي في الحصول على الفتوى', 'بيان عدم جواز الاعتماد على تطبيقات الذكاء الاصطناعي في استخراج الأحكام الشرعية والاستعاضة بها عن أهل العلم كما جاء في فتوى دار الإفتاء المصرية رقم 8784', '58268ad0-64e1-406b-8787-30de9fa077cd', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الوسائل تأخذ حكم مقاصدها: أداة مساعدة لا مصدر فتوى', 'لا يجوز شرعًا الاعتماد على تطبيقات الذكاء الاصطناعي في الحصول على الفتوى، وذلك لأن هذه البرامج تفتقر إلى معايير الدقة والضبط العلمي والشرعي التي يتحلى بها المفتي المؤهل، وتُخرج نتائج تحتمل الخطأ والصواب بل قد تأتي أحيانًا على خلاف الحقيقة الشرعية، لأنها لا تستند في استنباط الأحكام إلى منهج علمي رصين مبني على أصول الاستدلال الشرعي، كما تعجز عن مراعاة تغيّر الفتوى بتغيّر الزمان والمكان والعادات والأعراف، وهو أصل معتبر في الفقه الإسلامي لا تحسن الآلة تقديره. وقد استحضرت دار الإفتاء في تسبيب هذا الحكم قوله تعالى: ﴿وَسَخَّرَ لَكُم مَّا فِي السَّمَاوَاتِ وَمَا فِي الْأَرْضِ جَمِيعًا مِّنْهُ﴾ (الجاثية: 13)، مذكِّرة بأن كل تسخير للتقنية يبقى وسيلة تابعة في حكمها للغاية المقصودة منها، فمتى استُخدم الذكاء الاصطناعي أداة مساعدة في البحث والتنظيم دون اتخاذ نتائجه فتوى نهائية معتمدة كان ذلك جائزًا، أما اتخاذه مصدرًا مباشرًا للفتوى بديلاً عن الرجوع إلى أهل العلم المختصين فغير جائز.', 1),
    (v_lesson, 'examples', 'آية الأمر بسؤال أهل الذكر وحديث الإفتاء بغير علم', 'قال تعالى: ﴿فَاسْأَلُوا أَهْلَ الذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ﴾ (النحل: 43)، وهي الأصل القرآني الذي يوجب الرجوع في طلب العلم والفتوى إلى أهله المؤهلين، لا إلى أي وسيلة أخرى مهما بدت متاحة أو سريعة. وفي بيان خطر الفتوى بغير علم راسخ، عن عبد الله بن عمرو بن العاص رضي الله عنهما أن النبي صلى الله عليه وسلم قال: "إن الله لا يقبض العلم انتزاعًا ينتزعه من الناس، ولكن يقبض العلم بقبض العلماء، حتى إذا لم يبق عالمًا، اتخذ الناس رؤوسًا جهالًا، فسئلوا فأفتوا بغير علم، فضلوا وأضلوا" (متفق عليه، رواه البخاري 100 ومسلم 2673). فهذا الحديث يحذّر تحديدًا من مغبة الاستفتاء عند من ليس أهلًا للعلم الشرعي الرصين، وهو المعنى الذي بنت عليه دار الإفتاء منع الاعتماد على تطبيقات الذكاء الاصطناعي في الفتوى، لكونها لا تملك أهلية العالم المجتهد ولا ضبطه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8784: حكم استخدام تطبيقات الذكاء الاصطناعي (AI) في الاستفتاء (22 سبتمبر 2025م، مفتي الجمهورية أ.د/ نظير محمد عياد)', 1);
  END IF;

